INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1003', 'oppose', 'Elections & Voting Rights',
        'Allows election canvassers to certify results "without prejudice," inviting unnecessary and costly litigation even without evidence of irregularities. Undermines the finality of election results, enables endless legal challenges that fuel election denialism, and erodes public trust in the electoral process.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-25', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1037', 'oppose', 'Elections & Voting Rights',
        'Mandates tabulating machines not connect to the internet, imposing a Class 1 misdemeanor on election officials for violations. This is unnecessary as tabulation machines in Arizona have never been connected to the internet. Criminalizes election workers who are dedicated professionals serving their communities.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-04', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1038', 'oppose', 'Elections & Voting Rights',
        'Although amended to remove immediate release of voter names and ID numbers, the bill still threatens voter privacy. Requires county officials to transmit unaltered, sortable cast vote records to the Secretary of State as public records. Sortable, unrandomized records can be used to reconstruct how individuals voted, especially in small precincts.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-14', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1040', 'oppose', 'Elections & Voting Rights',
        'Would allow citizens to look up voter registration information. Could expand election-related vigilantism and suppress specific voter groups. Would increase costs for county administration and divert funds from election operations to maintaining an online portal.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-14', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1057', 'oppose', 'Elections & Voting Rights',
        'Requires paper ballots to include at least 3 of 10 watermark features. Increases cost of running elections and places undue burden on taxpayers. Raises risk of voter suppression because some watermark options require specialized equipment to detect, and voters may not realize their ballots are misprinted.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-14', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1060', 'oppose', 'Elections & Voting Rights',
        'Removes provisions allowing U.S. citizens born abroad who have never resided in the U.S. but whose parent is a registered AZ voter to vote using a Federal write-in early ballot. These citizens have a constitutional right to vote, are required to file U.S. taxes, and 18-year-old males must register for the Selective Service. Disenfranchises legal citizens.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-14', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1237', 'oppose', 'Elections & Voting Rights',
        'Expands the group responsible for preparing the Election Procedures Manual to include legislators. Politicizes a nonpartisan, technical document by inserting legislators into a process traditionally led by election administrators and subject-matter experts. Likely to slow updates and could result in procedures that advantage one party over another.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-28', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1289', 'oppose', 'Elections & Voting Rights',
        'Requires anyone providing money or in-kind support for election administration to certify they are not funded by foreign donations. Adds criminal and civil enforcement provisions that could trigger nuisance lawsuits. Regulates groups far removed from candidates and campaign messaging, doing little to address foreign influence while adding cost and risk.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-04', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1392', 'oppose', 'Elections & Voting Rights',
        'Gives governing bodies that canvass elections broad pre-canvass access to locations where election materials are handled or tabulated. Lacks clear definitions, timing limits, and safeguards, raising concerns about chain-of-custody breaches, delayed results, and risks to ballot security and voter confidence.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-04', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1425', 'oppose', 'Elections & Voting Rights',
        'Shortens the period for curing ballots from ten business days to six calendar days for federal elections and from five business days to five calendar days for others. The majority of AZ voters (85%) rely on mail-in voting. Reducing cure time could disenfranchise a large portion of the population, particularly elderly, Latino, and Black voters.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-04', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1489', 'oppose', 'Elections & Voting Rights',
        'Requires paid petition circulators to verbally identify themselves, provide their name and address, and wear visible identification. Complicates signature collection and could impede citizens'' ability to gather enough signatures for ballot initiatives. Delegates disqualification decisions to officials outside the Secretary of State''s office.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-11', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1568', 'oppose', 'Elections & Voting Rights',
        'Now titled "election systems; software; timekeeping; requirements." Imposes continuous time synchronization requirements on all election systems. An unfunded mandate that could cause significant financial burdens on county election offices, delays in results, and might be used to challenge election results without clear evidence of benefit.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-11', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1569', 'oppose', 'Elections & Voting Rights',
        'Prohibits Special Election Board members from facilitating voter registration, eliminating critical support for disabled, infirm, and hospitalized voters who rely on SEB assistance to meet registration deadlines. Shifting responsibility to uncompensated volunteer deputy registrars has proven ineffective and unsustainable.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-11', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1634', 'oppose', 'Elections & Voting Rights',
        'Requires the Department of Transportation to submit a copy of an applicant''s handwritten signature to the Secretary of State for voter signature comparison. A signature acquisition process is already in place. Adds another step to the MVD process, increases taxpayer costs, and introduces data privacy risks.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-11', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1655', 'oppose', 'Elections & Voting Rights',
        'Allows citizens to serve as election workers in lieu of jury duty. Could deplete the jury pool if too many opt out. Permits web-based training instead of hands-on training, which is insufficient for the high-pressure environment of a polling place. Requires constant coordination between the Jury Commissioner and County Recorder.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-18', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1746', 'oppose', 'Elections & Voting Rights',
        'Prevents teachers from serving as poll workers and removes principals'' ability to reject their school being designated as a polling place, regardless of consequences.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-18', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2805', 'oppose', 'Elections & Voting Rights',
        'Expands electronic signature collection for governing board candidates but requires candidates to designate party alignment. Although positioned as making signature collection easier, it appears to inject partisan politics into nonpartisan local elections for city, county, and school board positions.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-18', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2806', 'oppose', 'Elections & Voting Rights',
        'Mandates use of DHS SAVE verification system for county recorders, MVD, and AHCCCS. Introduces known risks of database errors, delays, and false mismatches that can wrongly block eligible citizens from registering to vote. Adds excessive reporting requirements and costs for Arizona taxpayers.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-28', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2901', 'oppose', 'Elections & Voting Rights',
        'Requires all voting machine components and manufacturing to be 100% U.S.-based by 2029. No evidence this enhances election security. Global supply chain makes full domestic sourcing exceptionally difficult and prohibitively expensive. Unlikely compliant machines would be in production by 2029, potentially forcing hand tabulation.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-28', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2902', 'oppose', 'Elections & Voting Rights',
        'Reaffirms support for the Electoral College. Five times in American history, the presidential candidate with the most votes did not win. The Electoral College is an outdated relic that puts decision-making power in the hands of politically motivated electors rather than the American people.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-28', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB4067', 'oppose', 'Elections & Voting Rights',
        'Requires county recorders to provide polling places with lists of inactive voters and create new voter status labels like "not registered," "suspense," "not eligible," and "cancelled." An unfunded mandate that adds administrative complexity, may fuel misleading claims about voter roll integrity, and disproportionately affects naturalized citizens, students, and low-income voters.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-18', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB4115', 'oppose', 'Elections & Voting Rights',
        'Requires paid petition circulators to verbally identify themselves, provide name and address, and wear visible identification. Complicates signature collection and could impede citizens'' ability to gather enough signatures for ballot initiatives. Delegates disqualification decisions to officials outside the Secretary of State''s office.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-18', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HCM2004', 'oppose', 'Elections & Voting Rights',
        'Non-binding memorial urging Congress to repeal the National Voter Registration Act of 1993 (NVRA). Repealing NVRA would harm voter access by creating new barriers to participation, increasing unequal access across states, and weakening civic engagement and voter turnout.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-21', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HCR2001', 'oppose', 'Elections & Voting Rights',
        'Proposes amending the Arizona Constitution to eliminate emergency voting, require government ID for every vote (including mail-in), and require voters to affirmatively request mail-in ballots every 2 years. Locks restrictive election rules into the Constitution, preventing future legislatures from fixing problems.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-21', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HCR2016', 'oppose', 'Elections & Voting Rights',
        'Would eliminate voting centers, sharply limit in-person early voting, and replace emergency voting with a strict precinct-based system capped at 2,500 voters per precinct. 89% of Arizonans support voting centers and nearly 50% of Maricopa County voters use them. Concurrent resolution bypasses the Governor and is difficult to change once approved by voters.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-28', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HCR2051', 'oppose', 'Elections & Voting Rights',
        'Requires paid petition circulators to verbally identify themselves and state their state of legal residence, and wear a visible badge. Complicates signature collection, could impede citizens'' ability to place initiatives on the ballot. Delegates disqualification decisions to officials outside the Secretary of State''s office.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-18', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SCR1001', 'oppose', 'Elections & Voting Rights',
        'Proposes amending the Arizona Constitution to add voter identification requirements, prohibit foreign contributions, and end early voting by 7:00 PM on the Friday before the general election. Uses a constitutional amendment to lock in restrictive election rules already codified in statute, reducing voter access without allowing future legislatures to fix problems.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-21', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SCR1002', 'oppose', 'Elections & Voting Rights',
        'Increases the threshold for itemizing individual campaign contributions from $100 to $200, reducing transparency by allowing more contributions to be reported only in aggregate. Makes it harder for voters, journalists, and oversight organizations to track who funds political campaigns.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-25', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SCR1013', 'oppose', 'Elections & Voting Rights',
        'Adds far-reaching provisions to Arizona''s ban on foreign money, requiring election vendors, campaign committees, and donors to sign sworn statements and keep records. Goes so far as to allow any citizen to bring civil action against anyone alleged to have violated the provisions.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-04', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SCR1014', 'oppose', 'Elections & Voting Rights',
        'Eliminates emergency voting and restricts mail-in ballots. Voters facing illness, caregiving, or unpredictable work schedules could lose their chance to vote. Prevents school principals from removing schools as voting locations and adds costly, unnecessary 50-day-prior testing requirement for voting equipment. Does not improve election security.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-04', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SCR1023', 'oppose', 'Elections & Voting Rights',
        'Restructures Arizona''s voter-approved Independent Redistricting Commission by expanding from 5 to 9 members, increasing partisan legislative appointments, adding geographic residency quotas, and requiring supermajority to approve maps. Weakens the independence voters intended when they created the commission through Proposition 106 in 2000.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-18', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SCR1027', 'oppose', 'Elections & Voting Rights',
        'Proposes a constitutional amendment to consolidate all elections onto general election day. Could lead to voter fatigue and undervoting due to lengthy ballots. Local elections like school board races are too important to be relegated to the end of a long ballot. Would infringe on charter city rights and undermine local control.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-11', datetime('now'));

