INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2008', 'oppose', 'Education',
        'Prohibits Arizona public school libraries from using public funds to pay professional association dues or memberships. Isolates school librarians from communities that provide critical training, literacy resources, and advocacy for intellectual freedom. Creates an inequitable educational landscape.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-20', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2076', 'oppose', 'Education',
        'Would allow schools to adopt policies authorizing employees to possess firearms on school grounds. Research shows guns on campus do not make schools safer and can disproportionately affect students of color and students with disabilities. Funding is only first-come, first-served reimbursement, resulting in inequitable outcomes.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-10', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2093', 'oppose', 'Education',
        'Repeals the requirement that mental health instruction be included in Arizona health education. Schools are the most reliable setting for mental health education, especially for marginalized and low-income students. Repeal would create uneven access and undermine efforts to reduce stigma and address youth mental health needs.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-10', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2240', 'oppose', 'Education',
        'Expands tuition waiver scholarships at universities and community colleges for children of veterans with disabilities. The waiver is neither merit-based nor need-based, and includes no additional state appropriations. Without funding, tuition at public institutions is likely to increase, shifting costs to other students.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-10', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2255', 'support', 'Education',
        'Expands the Teachers Academy scholarship for community college students from 2 to 4 years, supporting affordable pathways to teacher certification. Increases access to higher education and diversifies the teaching workforce. Aligns state law with community colleges'' new ability to offer 4-year degrees.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-17', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2312', 'oppose', 'Education',
        'Permits patriotic youth group representatives to address students during regular school hours. Eliminates local control, creates undue burdens on school officials, and reduces valuable learning time.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-03', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2423', 'oppose', 'Education',
        'Requires schools to enroll students in grades 6-8 in advanced math courses based on defined criteria. Opposes mandates that minimize local decision-making. Student placement should be collaborative, involving teachers, parents, counselors, and grades. Mandating collection of race/income/gender data exacerbates school segregation.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-17', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2478', 'oppose', 'Education',
        'Creates a largely partisan-appointed, state-level commission on student outcomes that risks undermining nonpartisan education governance and local control. Proposes using Classroom Site Fund dollars for statewide administration, conflicting with the fund''s statutory purpose of supporting direct instructional needs.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-17', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2575', 'oppose', 'Education',
        'Prohibits antisemitic conduct in public schools and higher education with severe punishments including civil litigation for teachers. While antisemitism has risen steeply since 2023, the bill''s penalties would have a chilling effect. Teachers and students should be allowed to freely discuss sensitive topics to prepare for civil discourse and critical thinking.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-10', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2764', 'support', 'Education',
        'Requires AZ State Board of Education to develop a Computer Science Proficiency program with a state seal for high school diplomas. The program is voluntary but unfunded, which may result in inequitable access. Supports preparing students for tech jobs but acknowledges without funding, many schools cannot implement it.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-18', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB4033', 'oppose', 'Education',
        'Introduces new ballot requirements for school bond measures mandating detailed lists of capital improvements, costs, and locations. This information is already provided in informational pamphlets mailed to each household. Complex ballot requirements are redundant and may confuse voters, leading to lower turnout.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-17', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB4106', 'support', 'Education',
        'Establishes the One Arizona Fellowship Program for high school graduates. Supports the workforce and educational pipeline, addresses community needs, and reduces financial barriers to college for low-income youth.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-17', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB4109', 'oppose', 'Education',
        'Known as "Michael''s Law," mandates school safety plans with 24-hour incident notification. Imposes criminal penalties including Class 1 misdemeanors on superintendents and school board members for non-compliance. Appears redundant as numerous school safety statutes already exist. Unfunded mandate that removes local decision-making.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-25', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1004', 'oppose', 'Education',
        'Allows ESA students to participate in interscholastic activities funded by public school funds. LWVAZ opposes distribution of public funds to private schools. Arizona public schools are underfunded and should not use resources for students attending private schools using ESA funds.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-18', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1370', 'oppose', 'Education',
        'Permits patriotic youth group representatives to address students during regular school hours. Eliminates local control, creates undue burdens on school officials, and reduces valuable learning time.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-04', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1424', 'oppose', 'Education',
        'Creates an unfunded mandate requiring annual firearm safety instruction for K-12 students. Removes curriculum decisions from the local level and shifts responsibility for gun safety onto children as young as five. Research shows school-based gun education alone is not a proven strategy; secure storage and mental health interventions are more effective.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-18', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1435', 'oppose', 'Education',
        'Makes it a class 5 felony for a public school or library employee to violate prohibitions on sexually explicit materials. Seeks to criminalize teachers and librarians who introduce diverse ideas. LWVAZ does not support censorship of programs or books. Library and school staff should not fear felony charges for helping students find resources.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-11', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1436', 'oppose', 'Education',
        'Uses complex details and language in school district bond and override ballots that may discourage voters from approving needed measures, thereby increasing the probability of educational inequities in some communities.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-02-11', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1572', 'oppose', 'Education',
        'Requires public schools to observe Celebrate Freedom Week with specified civics instruction topics that are already required by state standards. Mandating instruction during a specific week eliminates local control and forces adaptation regardless of existing curricula, including AP and IB classes.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-10', datetime('now'));

