-- Civil Liberties (6 bills)
-- ============================================================

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2249', 'oppose', 'Civil Liberties',
        'Expands Arizona''s Parents'' Bill of Rights by requiring written parental consent before school staff may use names or pronouns not aligned with a student''s sex. Allows parents to sue with mandatory minimum damages of $500,000 per violation against schools and $20,000 personal liability per employee. Raises serious concerns for transgender and gender-nonconforming students.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-20', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2589', 'oppose', 'Civil Liberties',
        'Creates a class 4 felony for allowing a minor to attend or be in the same building as an "adult-oriented performance." The vague definition could apply to theatrical performances and drag shows. Criminalizes parents and restricts their ability to choose experiences for their children. Already illegal for minors to enter strip clubs.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-25', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2136', 'oppose', 'Civil Liberties',
        'Creates two new Class 5 felony offenses called "civil terrorism" and "subversion," and increases penalties for obstructing a public road to a Class 6 felony. Makes "civil terrorism" a RICO qualifying offense, allowing protest organizers to be charged under organized crime statutes. Part of a nationwide trend to suppress constitutionally protected protest.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-25', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HCR2003', 'oppose', 'Civil Liberties',
        'Ballot proposition restricting transgender athletes from participating in sports by requiring teams based on biological sex. Targets a vulnerable population, denying them equal access to educational and social benefits of athletics. Exclusion is linked to adverse mental health outcomes. Concurrent resolution bypasses the Governor.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-01-20', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SCR1006', 'oppose', 'Civil Liberties',
        'Ballot measure restricting restroom use based on biological sex and requiring parental consent for pronoun use. Places educators in position of policing gender or facing liability. Stigmatizes vulnerable students by effectively outing them without consent. Combines provisions from vetoed 2025 bills SB1003 and SB1002 to bypass the Governor.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-03', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1741', 'oppose', 'Civil Liberties',
        'Requires school districts and charter schools to allow students to leave campus during the school day for religious instruction and award academic credit for it. Disrupts the school day. Allows lawsuits against non-compliant schools. An unfunded mandate that violates the separation of church and state.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-10', datetime('now'));

