-- Health & Reproductive Rights (4 bills)
-- ============================================================

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2060', 'oppose', 'Health & Reproductive Rights',
        'Prohibits public schools, community colleges, and universities from encouraging or helping someone obtain an abortion. Prevents abortion providers from teaching health education classes. Would withhold state funding from non-compliant schools. Censors fact-based health education materials and deprives individuals of critical, balanced information.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-25', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2364', 'oppose', 'Health & Reproductive Rights',
        'Imposes felony charges on medical providers who deliver abortion-inducing medications by mail, delivery, or courier. Also criminalizes pregnant women who accept the medication. Violates the recently passed Prop 139 and creates an undue burden on pregnant women.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-25', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2830', 'oppose', 'Health & Reproductive Rights',
        'Prohibits instruction on sexual activity, contraception, and abortion procedures while mandating fetal and prenatal development instruction. Prohibits abortion providers from providing instruction or materials. Removes local authority and would withhold state aid from non-compliant schools.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-25', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2040', 'oppose', 'Health & Reproductive Rights',
        'Requires employees of public educational institutions to include adoption practices in any discussions of contraception and STIs/STDs with students. An unfunded mandate that removes local control of curriculum. Emphasizes adoption without balancing against other risks and options.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-18', datetime('now'));

