INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1061', 'oppose', 'Criminal Justice',
        'Lowers the legal threshold for fentanyl sale charges from 200 grams to 9 grams, triggering Class 2 felony sentences with mandatory minimums of 4-18.5 years. Strict drug thresholds disproportionately harm communities of color and low-income individuals. Removes judicial discretion and emphasizes punitive measures over rehabilitation.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-11', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1110', 'support', 'Criminal Justice',
        'Expands eligibility for home confinement under electronic monitoring. Provides structured, supervised transition from incarceration to community reentry. Could reduce incarceration costs, support workforce participation, and improve reentry outcomes. Includes victim notification and monthly supervision fee.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-25', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'SB1140', 'support', 'Criminal Justice',
        'Allows people with certain misdemeanor convictions to have their records expunged, not just sealed. If approved, records would no longer appear in most background checks. Supports humane treatment and rehabilitation, promoting successful reentry into communities.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-25', datetime('now'));

INSERT OR REPLACE INTO org_recommendations (org_code, org_name, bill_number, position, category, description, source_url, source_date, scraped_at)
VALUES ('LWVAZ', 'League of Women Voters of Arizona', 'HB2265', 'support', 'Criminal Justice',
        'Eliminates court assessments of defendants'' ability to pay fines and fees, and shifts some fees from defendants to the court. Eases financial burden on defendants in poverty, reducing continued court involvement. Benefits courts by eliminating costly debt collection with little return.',
        'https://lwvaz.clubexpress.com/content.aspx?page_id=721&club_id=666348', '2026-03-17', datetime('now'));
